describe("DataTable - custom sort comparator", () => {
  it("uses custom compare function when provided", async () => {
    // Sort by string length ascending
    const lengthColumn = {
      key: "name",
      label: "Name",
      sortable: true,
      compare: (a: Item, b: Item) => a.name.length - b.name.length,
    };

    const { container } = renderTable({
      columns: [lengthColumn],
      data: [
        { id: "a", name: "Bob", value: 1, category: "x" },
        { id: "b", name: "Alexander", value: 2, category: "x" },
        { id: "c", name: "Jo", value: 3, category: "x" },
      ],
    });

    const rows = container.querySelectorAll('[data-testid="data-table-row"]');
    const cells = Array.from(rows).map((row) =>
      row.querySelector("td")?.textContent?.trim(),
    );
    // Jo (2) < Bob (3) < Alexander (9)
    expect(cells).toEqual(["Jo", "Bob", "Alexander"]);
  });
});

